const AWS = require('aws-sdk');
const { exec } = require('child_process');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    const bucket = event.Records[0].s3.bucket.name;
    const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
    const outputFormat = event.Records[0].s3.object.metadata.outputFormat;

    // Validate output format
    const allowedFormats = ['jpg', 'png', 'gif'];
    if (!allowedFormats.includes(outputFormat)) {
        throw new Error('Invalid output format');
    }

    const inputFilePath = `/tmp/${key}`;
    const outputFilePath = `/tmp/${key.split('.').slice(0, -1).join('.')}.${outputFormat}`;

    // Download the image from S3
    const params = {
        Bucket: bucket,
        Key: key,
    };

    const data = await s3.getObject(params).promise();
    require('fs').writeFileSync(inputFilePath, data.Body);

    // Execute ImageMagick convert command
    return new Promise((resolve, reject) => {
        exec(`convert ${inputFilePath} ${outputFilePath}`, async (error) => {
            if (error) {
                return reject(`Error converting image: ${error.message}`);
            }

            // Upload the converted image back to S3
            const outputParams = {
                Bucket: bucket,
                Key: `converted/${key.split('/').pop().split('.')[0]}.${outputFormat}`,
                Body: require('fs').createReadStream(outputFilePath),
                ContentType: `image/${outputFormat}`,
            };

            try {
                await s3.putObject(outputParams).promise();
                resolve(`Successfully converted and uploaded: ${outputParams.Key}`);
            } catch (uploadError) {
                reject(`Error uploading converted image: ${uploadError.message}`);
            }
        });
    });
};